INSERT INTO venues ("Id","Name","Slug","Description","Type","AddressLine","Suburb","Postcode","Latitude","Longitude","ContactEmail","ParkingInfo","TransitInfo","IsIdentityVerified","CreatedAtUtc") VALUES
('11111111-1111-1111-1111-111111111111','Grace Community Church of Vienna','grace-community-vienna','A welcoming congregation in the heart of Vienna with a large fellowship hall and several flexible meeting spaces available to local community groups during the week.',0,'120 Maple Avenue East','Vienna','22180',38.9012,-77.2653,'hall@gracevienna.org','Free on-site lot with about 40 spaces, plus unmetered street parking along Maple Avenue East.','On the Fairfax Connector 463 bus route and a short walk from the Vienna shops. Vienna/Fairfax-GMU Metro (Orange line) is a few minutes away by car.',true,'2026-06-13 00:00:00+00'),
('22222222-2222-2222-2222-222222222222','Vienna Presbyterian Church','vienna-presbyterian','Historic church near the W&OD trail offering a sanctuary annex and music room for recitals, rehearsals, and quiet community meetings.',0,'124 Park Street NE','Vienna','22180',38.9018,-77.2589,'rentals@viennapres.org','On-site lot behind the church with additional parking on Park Street NE. Bike racks by the W&OD trail entrance.','Steps from the W&OD trail for cyclists and walkers. Fairfax Connector buses stop on Maple Avenue, two blocks south.',true,'2026-06-13 00:00:00+00'),
('33333333-3333-3333-3333-333333333333','Oakton Baptist Church','oakton-baptist','Spacious suburban church with an indoor gymnasium and classrooms — popular for youth sports, camps, and weekend programs.',0,'10100 Blake Lane','Oakton','22124',38.8901,-77.3008,'facilities@oaktonbaptist.org','Large free parking lot with accessible bays right by the main entrance.','Best reached by car. The Fairfax Connector 605 stops on Blake Lane; Vienna Metro (Orange line) is about 10 minutes away by car.',true,'2026-06-13 00:00:00+00'),
('44444444-4444-4444-4444-444444444444','Dunn Loring United Methodist Church','dunn-loring-umc','Friendly neighborhood church near the Dunn Loring Metro with an arts studio and a free community lounge for local groups.',0,'2316 Gallows Road','Dunn Loring','22027',38.8989,-77.2287,'office@dunnloringumc.org','Free on-site parking off Gallows Road, with step-free access to the lounge and studio.','A 6-minute walk from Dunn Loring–Merrifield Metro (Orange line). Several Metrobus routes stop on Gallows Road outside.',true,'2026-06-13 00:00:00+00'),
('55555555-5555-5555-5555-555555555555','Merrifield Fellowship Church','merrifield-fellowship','Modern church near the Mosaic District offering a flexible main hall for events, classes, and worship gatherings.',0,'2920 Eskridge Road','Merrifield','22031',38.8742,-77.2289,'hello@merrifieldfellowship.org','Shared parking structure next door (free evenings and weekends) plus a small on-site lot.','A 10-minute walk from the Mosaic District. Dunn Loring Metro (Orange line) is one stop away on the 1A/1B Metrobus.',true,'2026-06-13 00:00:00+00');
INSERT INTO rooms ("Id","VenueId","Name","Slug","Description","Capacity","PricePerHour","Currency","HouseRules","Status","Amenities","AccessibilityFeatures","AcceptedActivityTypes","CreatedAtUtc") VALUES
('10000000-0000-0000-0000-000000000001','11111111-1111-1111-1111-111111111111','Fellowship Hall','fellowship-hall','Our largest space — a bright open hall with a stage, kitchen access, and seating for community dinners, performances, and large gatherings.',200,45.00,'USD','No alcohol. Clean-up required before departure. Amplified music until 9pm only.',1,1015,7,92,'2026-06-13 00:00:00+00'),
('10000000-0000-0000-0000-000000000002','11111111-1111-1111-1111-111111111111','Youth Activity Room','youth-activity-room','A carpeted multipurpose room ideal for children''s programs, tutoring, and small group activities. Free for nonprofit and youth use.',30,NULL,'USD','Adult supervision required for under-18 groups. Leave the room as you found it.',1,492,3,37,'2026-06-13 00:00:00+00'),
('20000000-0000-0000-0000-000000000001','22222222-2222-2222-2222-222222222222','Music Room','music-room','Acoustically warm room with an upright piano, perfect for choir rehearsals, recitals, and small concerts.',40,35.00,'USD','Piano use included. No food or drink near the instrument.',1,1476,1,112,'2026-06-13 00:00:00+00'),
('20000000-0000-0000-0000-000000000002','22222222-2222-2222-2222-222222222222','Garden Meeting Room','garden-meeting-room','A calm, light-filled room overlooking the church garden. Free for support groups and small community meetings.',18,NULL,'USD','Quiet hours respected — adjacent to the sanctuary. No amplified sound.',1,236,11,12,'2026-06-13 00:00:00+00'),
('30000000-0000-0000-0000-000000000001','33333333-3333-3333-3333-333333333333','Gymnasium','gymnasium','Full-size indoor gym with basketball hoops and floor markings for multiple sports. Ideal for youth leagues and active community programs.',120,60.00,'USD','Non-marking shoes required on the court. No outside food on the gym floor.',1,389,5,7,'2026-06-13 00:00:00+00'),
('30000000-0000-0000-0000-000000000002','33333333-3333-3333-3333-333333333333','Classroom B','classroom-b','Comfortable classroom with whiteboards and Wi-Fi, suited to tutoring, ESL classes, and small workshops.',25,25.00,'USD','Erase whiteboards after use. Stack chairs before leaving.',1,508,19,37,'2026-06-13 00:00:00+00'),
('30000000-0000-0000-0000-000000000003','33333333-3333-3333-3333-333333333333','Renovation Annex (coming soon)','renovation-annex','A new annex currently under renovation. Listing is being prepared and is not yet published.',50,40.00,'USD','TBD.',0,132,1,4,'2026-06-13 00:00:00+00'),
('40000000-0000-0000-0000-000000000001','44444444-4444-4444-4444-444444444444','Art Studio','art-studio','Wipe-clean studio with sinks, easels, and abundant natural light — built for painting classes, craft workshops, and maker meetups.',24,30.00,'USD','Cover tables before messy work. Dispose of materials responsibly.',1,492,3,49,'2026-06-13 00:00:00+00'),
('40000000-0000-0000-0000-000000000002','44444444-4444-4444-4444-444444444444','Community Lounge','community-lounge','Cozy lounge with comfortable seating and a coffee station — free for neighborhood associations and support groups.',20,NULL,'USD','Reset furniture and tidy the coffee station before you leave.',1,460,11,12,'2026-06-13 00:00:00+00'),
('50000000-0000-0000-0000-000000000001','55555555-5555-5555-5555-555555555555','Main Hall','main-hall','A versatile contemporary hall with a small stage, full A/V, and movable seating — works for everything from worship services to community workshops.',150,50.00,'USD','A/V technician available on request. Decorations must be free-standing — no wall fixings.',1,1023,15,124,'2026-06-13 00:00:00+00');
